const j = $json;

// Определяем тип update: callback_query или text message
if (j.callback_query) {
  // Это нажатие на кнопку
  return [{
    json: { _type: 'callback', raw: j },
    pairedItem: 0
  }];
} 
else if (j.message && j.message.text) {
  const text = (j.message.text || '').trim();
  // Это команда
  if (text.startsWith('/')) {
    return [{
      json: { _type: 'command', raw: j, text },
      pairedItem: 0
    }];
  }
}

// Что-то другое (фото, видео, не-команда) — игнорим
return [{
  json: { _type: 'skip' },
  pairedItem: 0
}];

const cb = $json.raw.callback_query;
if (!cb) return null;

const data = cb.data || '';
const chatId = cb.from.id.toString();
const messageId = cb.message.message_id;
const callbackQueryId = cb.id;
const managerName = ((cb.from.first_name || '') + ' ' + (cb.from.last_name || '')).trim();

const allowedChats = ['1009982311'];
if (!allowedChats.includes(chatId)) {
  return [{
    json: {
      action: 'unauthorized', phone: '', chatId, callbackQueryId, messageId,
      managerName, popupText: '⛔ Нет доступа', replyText: '⛔ Нет доступа'
    }
  }];
}

let action = 'unknown';
let phone = '';

if (data.startsWith('approve_photo_')) { action = 'approve_photo'; phone = data.substring(14); }
else if (data.startsWith('offer_course_')) { action = 'offer_course'; phone = data.substring(13); }
else if (data.startsWith('takeover_')) { action = 'takeover'; phone = data.substring(9); }
else if (data.startsWith('release_')) { action = 'release'; phone = data.substring(8); }
else if (data.startsWith('history_')) { action = 'history'; phone = data.substring(8); }
else if (data.startsWith('block_')) { action = 'block'; phone = data.substring(6); }
else if (data.startsWith('lead_')) { action = 'lead_card'; phone = data.substring(5); }

return [{ json: { action, phone, chatId, callbackQueryId, messageId, managerName, rawData: data } }];

const r = $json;
const cb = $('Parse callback').first().json;
const phone = cb.phone;

if (!r || !r.phone) {
  return [{ json: {
    replyText: `❌ Лид не найден: ${phone}`, popupText: 'Лид не найден',
    chatId: cb.chatId, callbackQueryId: cb.callbackQueryId, messageId: cb.messageId,
    phone, action: 'lead_card', managerName: cb.managerName, skipEdit: true
  } }];
}

const funnelLabels = {
  'new': '🆕 Новый', 'pitched': '💬 Запитчен', 'qualified': '✅ Квалифицирован',
  'event_interested': '🎉 Интерес к event', 'agency_interested': '💎 Интерес к agency',
  'ready_to_pay': '💳 Готов платить', 'paid_event': '✨ Оплатил event',
  'paid_agency': '💎 Оплатил agency', 'rejected_filter': '🚫 Не прошёл фильтр',
  'lost': '❌ Потерян'
};
const budgetLabels = {'low': 'низкий 💵', 'medium': 'средний 💵💵', 'high': 'высокий 💵💵💵'};

const name = r.whatsapp_name || r.name || '(без имени)';
const modeEmoji = r.mode === 'manual' ? '🛡️ MANUAL' : '🤖 AUTO';
const dnc = r.do_not_contact ? '🚫 DNC' : '';

let text = `👤 КАРТОЧКА ЛИДА\n━━━━━━━━━━━━━━\n`;
text += `📛 ${name}\n📞 ${r.phone}\n📱 ${r.source || '?'}\n${modeEmoji} ${dnc}\n`;
text += `\n📊 ${funnelLabels[r.funnel_stage] || r.funnel_stage}\n`;
if (r.interest) text += `🎯 Интерес: ${r.interest}\n`;

text += `\n🧠 ПРОФИЛЬ:\n`;
if (r.age) text += `   Возраст: ${r.age}\n`;
if (r.profession) text += `   Профессия: ${r.profession}\n`;
if (r.is_single !== null) text += `   Холост: ${r.is_single ? 'да ✓' : 'нет ✗'}\n`;
if (r.budget_signal) text += `   Бюджет: ${budgetLabels[r.budget_signal]}\n`;
if (r.photo_received) text += `   Фото: ✓\n`;
if (r.objection_count > 0) text += `   Возражений: ${r.objection_count}\n`;
if (r.escort_mention_count > 0) text += `   ⚠️ Эскорт-упоминаний: ${r.escort_mention_count}\n`;

text += `\n💬 Сообщений: ${r.msg_count || 0}\n`;

if (r.last_inbound) text += `\n👤 Последнее от лида:\n«${(r.last_inbound || '').substring(0, 120)}»\n`;
if (r.last_outbound) text += `\n🤖 Последнее от бота:\n«${(r.last_outbound || '').substring(0, 120)}»\n`;

if (r.escalate_reason) text += `\n⚡ ${r.escalate_reason}\n`;

return [{ json: {
  replyText: text,
  popupText: `👤 ${name} • ${funnelLabels[r.funnel_stage] || r.funnel_stage}`,
  chatId: cb.chatId, callbackQueryId: cb.callbackQueryId, messageId: cb.messageId,
  phone, action: 'lead_card', managerName: cb.managerName, skipEdit: true
} }];

